# Module: shapes
# Provides base shape classes, interfaces, and enums for geometric operations
from geometry import Point

class IMeasurable:
    """Interface for objects that have a measurable dimension."""
    def measure(self) -> float:
        ...

class IDrawable:
    """Interface for objects that can be drawn."""
    @virtual
    def draw(self) -> str:
        ...

enum ShapeType:
    CIRCLE = 1
    RECTANGLE = 2
    TRIANGLE = 3

@abstract
class Shape:
    """Abstract base class for all geometric shapes."""
    shape_type: ShapeType
    center: Point

    def __init__(self, center: Point):
        self.center = center
        self.shape_type = ShapeType.CIRCLE

    @abstract
    def area(self) -> float:
        ...

    @abstract
    def perimeter(self) -> float:
        ...

    @virtual
    def description(self) -> str:
        return "A shape"

    @virtual
    def draw(self) -> str:
        return "Drawing a shape"

