# Module: utils
# Utility functions and constants for shape operations
from shapes import Shape, ShapeType
from geometry import Rectangle, Point

@static
const PI: float = 3.14159

class ShapeCounter:
    """Counts shapes by type."""
    counts: dict[str, int]

    def __init__(self):
        self.counts = {}

    def register(self, shape_type: str) -> None:
        if shape_type not in self.counts:
            self.counts[shape_type] = 0
        self.counts[shape_type] += 1

    def get_count(self, shape_type: str) -> int:
        if shape_type in self.counts:
            return self.counts[shape_type]
        return 0

    def total(self) -> int:
        total_count: int = 0
        for count in self.counts.values():
            total_count += count
        return total_count

class Box(Rectangle):
    """A 3D box, extends Rectangle with depth."""
    depth: float

    def __init__(self, top_left: Point, width: float, height: float, depth: float):
        super().__init__(top_left, width, height)
        self.depth = depth

    def volume(self) -> float:
        face_area: float = super().area()
        return face_area * self.depth

    @override
    def area(self) -> float:
        # Surface area of box
        w: float = self.width
        h: float = self.height
        d: float = self.depth
        return 2.0 * (w * h + w * d + h * d)

